import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicThreeCoins() {
        // [1,2,5] amount=11: 5+5+1 = 3 coins
        assertEquals(3, new Solution().coinChange(new int[]{1, 2, 5}, 11));
    }

    @Test
    void impossibleAmount() {
        // [2] amount=3: can't make odd number with only 2s
        assertEquals(-1, new Solution().coinChange(new int[]{2}, 3));
    }

    @Test
    void amountZero() {
        // amount=0 always requires 0 coins regardless of denominations
        assertEquals(0, new Solution().coinChange(new int[]{1, 2, 5}, 0));
    }

    @Test
    void singleCoinExactMatch() {
        // [5] amount=5: exactly one coin
        assertEquals(1, new Solution().coinChange(new int[]{5}, 5));
    }

    @Test
    void singleCoinMultiple() {
        // [2,5,10] amount=6: 2+2+2 = 3 coins (greedy with 5 would need 5+1? but 1 not in set)
        assertEquals(3, new Solution().coinChange(new int[]{2, 5, 10}, 6));
    }

    @Test
    void largeAmountLargeCoins() {
        // [186,419,83,408] amount=6249 â†’ 20 (known LeetCode answer)
        assertEquals(20, new Solution().coinChange(new int[]{186, 419, 83, 408}, 6249));
    }

    @Test
    void singleCoinNotDivisible() {
        // [3] amount=7: 3+3+1? but 1 not available â€” impossible
        assertEquals(-1, new Solution().coinChange(new int[]{3}, 7));
    }
}
